const payload = $input.first().json.body || $input.first().json;
const ig = payload.user_credentials?.instagram || {};

// La Graph API de Instagram acepta periodos: day, week, days_28
const periodMap = { '7d': 'week', '30d': 'days_28', '90d': 'days_28' };

return [{
  json: {
    has_instagram: Boolean(ig.access_token && ig.instagram_account_id),
    access_token: ig.access_token || '',
    instagram_account_id: ig.instagram_account_id || '',
    platform: payload.platform || 'all',
    period: periodMap[payload.period] || 'days_28',
    requested_period: payload.period || '30d'
  }
}];

const data = $input.first().json;
const ctx = $('Extract Credentials').first().json;

const result = {
  platform: 'instagram',
  period: ctx.requested_period,
  insights: data.data || data
};

if (ctx.platform === 'all' || ctx.platform === 'linkedin') {
  result.note = 'Analytics de LinkedIn aun no disponibles (requiere LinkedIn Marketing Developer Platform). Se muestran solo metricas de Instagram.';
}

return [{ json: result }];

return [{
  json: {
    error: true,
    service: 'social_analytics',
    message: 'Instagram no esta conectado. Conectalo en Conexiones (/settings/integrations) para ver tus metricas. Analytics de LinkedIn aun no esta soportado.'
  }
}];
